1	//! Layer 1 External API Gateway.
2	//!
3	//! How external AI agents connect to the Agent Nervous System.
4	//! Three protocols, one gateway:
5	//!
6	//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
7	//!   for Claude, `ChatGPT`, and other MCP-compatible agents.
8	//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
9	//! - **WebSocket**: Streaming events for real-time agent feedback.
10	//!
11	//! All connections are authenticated (API key), rate-limited, and
12	//! budget-tracked before any internal gRPC call is made.
13	
14	pub mod auth;
15	pub mod client;
16	pub mod mcp;
17	pub mod metrics;
18	pub mod rest;
19	pub mod ws;
20	
21	use std::net::SocketAddr;
22	use axum::routing::{get, post};
23	use axum::Router;
24	
25	use std::sync::Arc;
26	
27	use ans_goal::GoalStateStore;
28	use auth::SharedKeyRegistry;
29	use client::InternalClient;
30	use mcp::McpServer;
31	use metrics::Metrics;
32	use rest::ApiRouter;
33	use ws::WebSocketServer;
34	
35	/// Shared gateway state, created once at startup.
36	#[derive(Clone)]
37	pub struct Gateway {
38	    key_registry: SharedKeyRegistry,
39	    pub metrics: Arc<Metrics>,
40	    mcp: McpServer,
41	    rest: ApiRouter,
42	    ws: WebSocketServer,
43	}
44	
45	impl Gateway {
46	    /// Initialize the gateway: load API keys, connect to the daemon.
47	    ///
48	    /// If `goal_store` is provided, a background task bridges goal state
49	    /// notifications to all connected WebSocket clients.
50	    pub async fn init(
51	        grpc_port: u16,
52	        goal_store: Option<GoalStateStore>,
53	    ) -> Result<Self, Box<dyn std::error::Error>> {
54	        let key_registry = Arc::new(auth::KeyRegistry::load(None)?);
55	        let internal = InternalClient::connect(grpc_port).await?;
56	        let metrics = Arc::new(Metrics::new());
57	        let mcp = McpServer::new(internal.clone());
58	        let rest = ApiRouter::new(internal.clone());
59	        let ws = WebSocketServer::new(internal);
60	
61	        // Bridge goal state changes to WebSocket clients
62	        if let Some(store) = &goal_store {
63	            let ws_clone = ws.clone();
64	            let mut rx = store.subscribe();
65	            tokio::spawn(async move {
66	                while let Ok(notification) = rx.recv().await {
67	                    let json = serde_json::to_string(&serde_json::json!({
68	                        "type": "goal_update",
69	                        "goal_id": notification.goal_id.to_string(),
70	                        "progress": notification.progress,
71	                        "status": format!("{:?}", notification.status),
72	                        "message": notification.message,
73	                    }))
74	                    .unwrap_or_default();
75	                    ws_clone.push_event(&json);
76	                }
77	            });
78	            tracing::info!("WebSocket bridge: forwarding goal updates to clients");
79	        }
80	
81	        Ok(Self {
82	            key_registry,
83	            metrics,
84	            mcp,
85	            rest,
86	            ws,
87	        })
88	    }
89	
90	    /// Build the axum router.
91	    ///
92	    /// **One flat Router** — no `nest()`, no `merge()`.
93	    /// axum 0.7 `nest()` drops `{param}` captures and `merge()` with
94	    /// `route_layer` silently discards parameterized routes.
95	    /// A single flat Router with path-aware auth is the only reliable pattern.
96	    pub fn router(&self) -> Router {
97	        let rest = self.rest.clone();
98	        let mcp = self.mcp.clone();
99	        let ws = self.ws.clone();
100	        let registry = Arc::clone(&self.key_registry);
101	        let metrics_arc = Arc::clone(&self.metrics);
102	
103	        // Path-aware auth middleware: skips public routes, enforces API key on
104	        // everything else.
105	        let auth_mw = axum::middleware::from_fn({
106	            let registry = Arc::clone(&registry);
107	            move |request: axum::extract::Request, next: axum::middleware::Next| {
108	                let registry = Arc::clone(&registry);
109	                async move {
110	                    let path = request.uri().path().to_owned();
111	
112	                    // Public routes — no API key required.
113	                    if path == "/api/v1/health"
114	                        || path == "/api/v1/metrics"
115	                        || path == "/mcp"
116	                        || path == "/ws"
117	                        || path == "/"
118	                    {
119	                        return next.run(request).await;
120	                    }
121	
122	                    let api_key = auth::extract_api_key(request.headers(), None);
123	                    let valid = api_key
124	                        .as_ref()
125	                        .and_then(|k| registry.validate(k))
126	                        .is_some();
127	                    if valid {
128	                        next.run(request).await
129	                    } else {
130	                        let body = if api_key.is_some() {
131	                            r#"{"error":"invalid API key"}"#
132	                        } else {
133	                            r#"{"error":"missing X-API-Key header"}"#
134	                        };
135	                        axum::response::Response::builder()
136	                            .status(axum::http::StatusCode::UNAUTHORIZED)
137	                            .body(axum::body::Body::from(body))
138	                            .expect("building a 401 response is infallible")
139	                    }
140	                }
141	            }
142	        });
143	
144	        // Single flat Router — every route registered directly.
145	        // No nest(), no merge() — both break {param} captures in axum 0.7.
146	        Router::new()
147	            // ── Public routes ──────────────────────────────────────
148	            .route(
149	                "/",
150	                get(|| async {
151	                    axum::response::Html(include_str!("../../../static/dashboard.html"))
152	                }),
153	            )
154	            .route(
155	                "/mcp",
156	                post(
157	                    move |body: axum::extract::Json<serde_json::Value>| async move {
158	                        let response = mcp.handle_request(body.0).await;
159	                        axum::Json(response)
160	                    },
161	                ),
162	            )
163	            .route(
164	                "/ws",
165	                get(
166	                    move |ws_upgrade: axum::extract::ws::WebSocketUpgrade| async move {
167	                        ws.handle_upgrade(ws_upgrade).await
168	                    },
169	                ),
170	            )
171	            .route(
172	                "/api/v1/health",
173	                get({
174	                    let rest = rest.clone();
175	                    move || {
176	                        let rest = rest.clone();
177	                        async move { rest.health().await }
178	                    }
179	                }),
180	            )
181	            .route(
182	                "/api/v1/metrics",
183	                get(move || {
184	                    let m = Arc::clone(&metrics_arc);
185	                    async move { m.render() }
186	                }),
187	            )
188	            // ── Session routes ─────────────────────────────────────
189	            .route(
190	                "/api/v1/sessions",
191	                post({
192	                    let rest = rest.clone();
193	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
194	                        rest.create_session(body).await
195	                    }
196	                }),
197	            )
198	            .route(
199	                "/api/v1/sessions/{id}/navigate",
200	                post({
201	                    let rest = rest.clone();
202	                    move |axum::extract::Path(id): axum::extract::Path<String>,
203	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
204	                        rest.navigate(&id, body).await
205	                    }
206	                }),
207	            )
208	            .route(
209	                "/api/v1/sessions/{id}/execute",
210	                post({
211	                    let rest = rest.clone();
212	                    move |axum::extract::Path(id): axum::extract::Path<String>,
213	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
214	                        rest.execute_action(&id, body).await
215	                    }
216	                }),
217	            )
218	            .route(
219	                "/api/v1/sessions/{id}/screenshot",
220	                post({
221	                    let rest = rest.clone();
222	                    move |axum::extract::Path(id): axum::extract::Path<String>,
223	                          axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
224	                        rest.screenshot(&id, body).await
225	                    }
226	                }),
227	            )
228	            .route(
229	                "/api/v1/sessions/{id}/dom",
230	                get({
231	                    let rest = rest.clone();
232	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
233	                        rest.get_dom(&id).await
234	                    }
235	                }),
236	            )
237	            // ── Goal routes ────────────────────────────────────────
238	            .route(
239	                "/api/v1/goals",
240	                post({
241	                    let rest = rest.clone();
242	                    move |axum::extract::Json(body): axum::extract::Json<serde_json::Value>| async move {
243	                        rest.create_goal(body).await
244	                    }
245	                }),
246	            )
247	            .route(
248	                "/api/v1/goals/{id}",
249	                get({
250	                    let rest = rest.clone();
251	                    move |axum::extract::Path(id): axum::extract::Path<String>| async move {
252	                        rest.get_goal(&id).await
253	                    }
254	                }),
255	            )
256	            // Auth middleware applies to everything, but skips public paths.
257	            .route_layer(auth_mw)
258	    }
259	
260	    /// Start the gateway HTTP server on the given address.
261	    /// Blocks until the server exits.
262	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
263	        let router = self.router();
264	
265	        tracing::info!("Gateway starting on {}", addr);
266	
267	        let listener = tokio::net::TcpListener::bind(addr).await?;
268	        axum::serve(listener, router).await?;
269	
270	        Ok(())
271	    }
272	}
