396	    async fn create_goal(
397	        &self,
398	        request: Request<CreateGoalRequest>,
399	    ) -> Result<Response<GoalState>, Status> {
400	        let req = request.into_inner();
401	        let state = self
402	            .goals
403	            .create_goal(&req.description, &req.context, req.max_steps as u32)
404	            .map_err(|e| Status::internal(e.to_string()))?;
405	
406	        self.metrics.inc_goals(1);
407	
408	        // Spawn Python AgentLoop in background
409	        let goal_id = state.goal_id.to_string();
410	        let goal_uuid = state.goal_id;
411	        let description = state.description.clone();
412	        let nerves_dir = self.nerves_dir.clone();
413	        let goals = self.goals.clone();
414	        tokio::spawn(async move {
415	            // Auto-detect venv Python relative to nerves_dir
416	            let python = if let Some(ref dir) = nerves_dir {
417	                let venv_python = dir.join(".venv").join("Scripts").join("python.exe");
418	                if venv_python.exists() {
419	                    venv_python
420	                } else {
421	                    let unix_venv = dir.join(".venv").join("bin").join("python");
422	                    if unix_venv.exists() { unix_venv } else { std::path::PathBuf::from("python") }
423	                }
424	            } else {
425	                std::path::PathBuf::from("python")
426	            };
427	
428	            let mut cmd = tokio::process::Command::new(&python);
429	            cmd.args(["-m", "ans_nerves", "run", "--goal-id", &goal_id, &description])
430	                .kill_on_drop(true);
431	            if let Some(ref dir) = nerves_dir {
432	                cmd.current_dir(dir);
433	            }
434	            match cmd.output().await {
435	                Ok(output) => {
436	                    if output.status.success() {
437	                        tracing::info!(%goal_id, "Python AgentLoop completed");
438	                    } else {
439	                        let stderr = String::from_utf8_lossy(&output.stderr);
440	                        tracing::error!(%goal_id, %stderr, "Python AgentLoop failed");
441	                        let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed);
442	                    }
443	                }
444	                Err(e) => {
445	                    tracing::error!(%goal_id, error=%e, "Failed to spawn Python AgentLoop");
446	                    let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed);
447	                }
448	            }
449	        });
450	
451	        Ok(Response::new(ans_goal::serialization::goal_state_to_proto(
452	            &state,
453	        )))
454	    }
