517	    async fn subscribe_goal_updates(
518	        &self,
519	        request: Request<GoalStateRequest>,
520	    ) -> Result<Response<Self::SubscribeGoalUpdatesStream>, Status> {
521	        let req = request.into_inner();
522	        let goal_id = if req.goal_id.is_empty() {
523	            None
524	        } else {
525	            Some(
526	                Uuid::parse_str(&req.goal_id)
527	                    .map_err(|_| Status::invalid_argument("invalid goal_id"))?,
528	            )
529	        };
530	
531	        let rx = self.goals.subscribe();
532	        let stream = BroadcastStream::new(rx).filter_map(move |result| {
533	            let gid = goal_id;
534	            let notification = result.ok()?;
535	            if gid.is_none_or(|id| notification.goal_id == id) {
536	                Some(Ok(ans_proto::ans::GoalUpdate {
537	                    goal_id: notification.goal_id.to_string(),
538	                    event_type: goal_status_event(notification.status),
539	                    message: notification.message,
540	                    progress: notification.progress,
541	                    sub_goal: None,
542	                }))
543	            } else {
544	                None
545	            }
546	        });
547	
548	        Ok(Response::new(Box::pin(stream)))
549	    }
