678	    async fn scan_injections(
679	        &self,
680	        request: Request<InjectionScanRequest>,
681	    ) -> Result<Response<InjectionScanResult>, Status> {
682	        let req = request.into_inner();
683	
684	        self.metrics.inc_immune_scans();
685	        let detector = ans_immune::InjectionDetector;
686	        let start = std::time::Instant::now();
687	        let result = detector.scan(&req.url, &req.page_content);
688	        let scan_time_us = start.elapsed().as_micros() as i64;
689	
690	        let mut proto = ans_immune::serialization::injection_result_to_proto(&result);
691	        proto.scan_time_us = scan_time_us;
692	
693	        Ok(Response::new(proto))
694	    }
