696	    async fn check_action(
697	        &self,
698	        request: Request<ActionCheckRequest>,
699	    ) -> Result<Response<ActionCheckResponse>, Status> {
700	        let req = request.into_inner();
701	        let session_id = parse_uuid(&req.session_id, "session_id")?;
702	
703	        // Get current URL for context
704	        let url = self.sessions.get_url(session_id).await.unwrap_or_default();
705	
706	        // Build scannable text from the action itself
707	        let action = req.action.as_ref();
708	        let action_text = action.map_or(String::new(), |a| {
709	            format!("{} {} {}", a.action_type, a.selector, a.value)
710	        });
711	
712	        // Run both immune checks
713	        self.metrics.inc_immune_scans();
714	        let classifier = ans_immune::DistractionClassifier;
715	        let distractions = classifier.classify(&url, &action_text, &action_text);
716	
717	        let detector = ans_immune::InjectionDetector;
718	        let injection = detector.scan(&url, &action_text);
719	
720	        let response =
721	            ans_immune::serialization::build_action_check_response(&distractions, &injection);
722	
723	        Ok(Response::new(response))
724	    }
