927	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
928	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
929	fn proto_to_core_eye_report(
930	    proto: &ans_proto::ans::EyeReport,
931	) -> Option<ans_core::signal::EyeReport> {
932	    use ans_proto::ans::eye_report::Content;
933	
934	    let eye_name = match proto.eye_name.as_str() {
935	        "dom_reader" => EyeName::DomReader,
936	        "vision" => EyeName::Vision,
937	        "page_diff" => EyeName::PageDiff,
938	        "goal_verifier" => EyeName::GoalVerifier,
939	        "error_detector" => EyeName::ErrorDetector,
940	        _ => return None,
941	    };
942	
943	    let content = match &proto.content {
944	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
945	            elements: vec![],
946	            interactive: vec![],
947	            mode: dom
948	                .dom
949	                .as_ref()
950	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
951	                    "text_only" => DistillMode::TextOnly,
952	                    "input_fields" => DistillMode::InputFields,
953	                    _ => DistillMode::AllFields,
954	                }),
955	        },
956	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
957	            visible_elements: v.visible_elements.clone(),
958	            overlays: v.overlays.clone(),
959	            blocked_regions: v.blocked_regions.clone(),
960	            page_type: v.page_type.clone(),
961	            anomalies: v.anomalies.clone(),
962	            raw_response: v.raw_response.clone(),
963	        },
964	        Some(Content::Diff(d)) => {
965	            let diff_report = d.diff.as_ref();
966	            EyeReportContent::DiffReport {
967	                added: diff_report.map_or(vec![], |r| {
968	                    r.added.iter().map(|e| e.selector.clone()).collect()
969	                }),
970	                removed: diff_report.map_or(vec![], |r| {
971	                    r.removed.iter().map(|e| e.selector.clone()).collect()
972	                }),
973	                modified: diff_report.map_or(vec![], |r| {
974	                    r.modified.iter().map(|m| m.selector.clone()).collect()
975	                }),
976	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
977	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
978	            }
979	        }
980	        Some(Content::Verification(v)) => EyeReportContent::Verification {
981	            sub_goal_advanced: v.criteria_status == "met",
982	            confidence: v.confidence,
983	            reasoning: v.reasoning.clone(),
984	            criteria_status: v.criteria_status.clone(),
985	        },
986	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
987	            failure_type: e.failure_type.clone(),
988	            description: e.description.clone(),
989	            recovery_actions: e.recovery_actions.clone(),
990	            should_retry: e.should_retry,
991	            max_retries: e.max_retries as u32,
992	        },
993	        None => return None,
994	    };
995	
996	    Some(ans_core::signal::EyeReport {
997	        eye_name,
998	        timestamp: chrono::Utc::now(),
999	        confidence: proto.confidence,
1000	        goal_relevance: proto.goal_relevance,
1001	        content,
1002	    })
1003	}
