1005	/// Format the oneof eye report content into a readable string.
1006	fn format_eye_content(content: Option<&ans_proto::ans::eye_report::Content>) -> String {
1007	    use ans_proto::ans::eye_report::Content;
1008	    match content {
1009	        Some(Content::Dom(dom)) => {
1010	            format!(
1011	                "DOM: {} elements, {} interactive",
1012	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
1013	                dom.focused_elements.len()
1014	            )
1015	        }
1016	        Some(Content::Vision(v)) => {
1017	            format!(
1018	                "Vision: {} visible, {} overlays, type={}",
1019	                v.visible_elements.len(),
1020	                v.overlays.len(),
1021	                v.page_type
1022	            )
1023	        }
1024	        Some(Content::Diff(d)) => {
1025	            format!(
1026	                "Diff: {}% visual change",
1027	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
1028	            )
1029	        }
1030	        Some(Content::Verification(v)) => {
1031	            format!(
1032	                "Verify: {} (confidence={:.0}%)",
1033	                v.criteria_status,
1034	                v.confidence * 100.0
1035	            )
1036	        }
1037	        Some(Content::Error(e)) => {
1038	            format!("Error: {} — {}", e.failure_type, e.description)
1039	        }
1040	        None => "no content".into(),
1041	    }
1042	}
