102	    <input type="text" id="goalInput" placeholder="What should the agent do? e.g., Search for flights from Delhi to Mumbai on June 5" autofocus>
103	    <button id="submitBtn" onclick="submitGoal()">▶ Run</button>
104	    <button onclick="toggleMode()" style="background:transparent;border:1px solid var(--border);font-size:.8rem;padding:14px 16px" title="Toggle fast/thorough mode">Fast</button>
105	  </div>
106	
107	  <div class="glass eyes-panel">
108	    <h2>5 Eyes — Perception</h2>
109	    <div class="eyes-grid">
110	      <div class="glass eye-tile" id="eye-dom_reader"><div class="eye-icon">🔍</div><div class="eye-name">DOM Reader</div><div class="eye-status">idle</div></div>
111	      <div class="glass eye-tile" id="eye-vision"><div class="eye-icon">👁</div><div class="eye-name">Vision</div><div class="eye-status">idle</div></div>
112	      <div class="glass eye-tile" id="eye-page_diff"><div class="eye-icon">⚡</div><div class="eye-name">Page Diff</div><div class="eye-status">idle</div></div>
113	      <div class="glass eye-tile" id="eye-goal_verifier"><div class="eye-icon">✅</div><div class="eye-name">Goal Verifier</div><div class="eye-status">idle</div></div>
114	      <div class="glass eye-tile" id="eye-error_detector"><div class="eye-icon">🚨</div><div class="eye-name">Error Detector</div><div class="eye-status">idle</div></div>
115	    </div>
116	  </div>
117	
118	  <div class="goals-grid" id="goalsGrid">
119	    <div class="glass empty-state"><div class="empty-icon">🎯</div><p>No active goals. Submit a goal above to get started.</p></div>
120	  </div>
121	</div>
122	
123	<script>
124	const API = '';
125	let ws=null,goals={},wsConnected=false,fastMode=false;
126	
127	function connectWS(){
128	  ws=new WebSocket(`ws://${location.host}/ws`);
129	  ws.onopen=()=>{wsConnected=true;document.getElementById('wsDot').className='status-dot connected';document.getElementById('wsStatus').textContent='Connected'};
130	  ws.onclose=()=>{wsConnected=false;document.getElementById('wsDot').className='status-dot disconnected';document.getElementById('wsStatus').textContent='Disconnected - reconnecting...';setTimeout(connectWS,2000)};
131	  ws.onmessage=(e)=>{try{handleEvent(JSON.parse(e.data))}catch(ex){}};
132	}
133	function handleEvent(d){
134	  if(d.type==='goal_created'){goals[d.goal_id]=d;renderGoals()}
135	  else if(d.type==='goal_update'){
136	    if(goals[d.goal_id]){goals[d.goal_id].progress=d.progress;goals[d.goal_id].status=d.status;if(d.sub_goals)goals[d.goal_id].sub_goals=d.sub_goals}else{goals[d.goal_id]=d}
137	    renderGoals();
138	    if(d.eye_updates)for(let[k,v]of Object.entries(d.eye_updates)){let el=document.getElementById('eye-'+k.replace('_','-'));if(el){el.className='glass eye-tile '+(v==='active'?'active':v==='error'?'error':v==='warning'?'warning':'');el.querySelector('.eye-status').textContent=v}}
139	  }else if(d.type==='eye_report'){let el=document.getElementById('eye-'+d.eye_name);if(el){el.className='glass eye-tile active';el.querySelector('.eye-status').textContent='active (confidence: '+(d.confidence||0).toFixed(2)+')'}}
140	}
141	async function submitGoal(){
142	  let goal=document.getElementById('goalInput').value.trim();if(!goal)return;
143	  let btn=document.getElementById('submitBtn');btn.disabled=true;btn.textContent='Running...';
144	  try{
145	    let r=await fetch(API+'/api/v1/goals',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({description:goal,max_steps:50,context:fastMode?'mode=fast':''})});
146	    if(r.ok){document.getElementById('goalInput').value='';showToast('Goal created','success')}else{showToast('Failed to create goal','error')}
147	  }catch(e){showToast('Error: '+e.message,'error')}
148	  btn.disabled=false;btn.textContent='▶ Run';
149	}
150	function renderGoals(){
151	  let entries=Object.entries(goals).sort((a,b)=>b[1].created_at-a[1].created_at),grid=document.getElementById('goalsGrid');
152	  if(!entries.length){grid.innerHTML='<div class="glass empty-state"><div class="empty-icon">🎯</div><p>No active goals. Submit a goal above to get started.</p></div>';return}
153	  document.getElementById('activeCount').textContent=entries.filter(([,g])=>g.status==='active').length;
154	  grid.innerHTML=entries.map(([id,g])=>{
155	    let pct=Math.round((g.progress||0)*100),sc=g.status==='completed'?'completed':g.status==='failed'?'failed':'';
156	    let sg=g.sub_goals||[],shtml=sg.length?('<div class="sub-goals">'+sg.map(s=>{let dc=s.status==='Done'?'done':s.status==='Active'?'active':s.status==='Blocked'?'blocked':'pending';return`<div class="sub-goal-item"><span class="sub-goal-dot ${dc}"></span>${e(s.description)}</div>`}).join('')+'</div>'):'';
157	    return`<div class="glass goal-card ${sc}"><div class="goal-title">${e(g.description)}</div><div class="goal-meta"><span>${pct}%</span><span style="text-transform:capitalize">${g.status}</span></div><div class="progress-bar"><div class="progress-fill" style="width:${pct}%"></div></div>${shtml}</div>`
158	  }).join('')
159	}
160	function toggleMode(){fastMode=!fastMode;document.getElementById('modeBadge').textContent=fastMode?'Fast':'Thorough';document.getElementById('modeBadge').className='mode-badge '+(fastMode?'fast':'thorough');showToast(`Mode: ${fastMode?'Fast (skip Eyes)':'Thorough (full 5 Eyes)'}`,'success')}
161	function showToast(m,t){let el=document.createElement('div');el.className='toast '+t;el.textContent=m;document.body.appendChild(el);setTimeout(()=>el.remove(),4000)}
162	function e(s){let d=document.createElement('div');d.textContent=s;return d.innerHTML}
163	document.getElementById('goalInput').addEventListener('keydown',e=>{if(e.key==='Enter')submitGoal()});
164	connectWS();
165	</script>
166	</body>
167	</html>
