7	use tokio::sync::broadcast;
8	use uuid::Uuid;
9	
10	/// A goal progress update pushed to all subscribers.
11	#[derive(Debug, Clone)]
12	pub struct GoalUpdate {
13	    pub goal_id: Uuid,
14	    pub progress: f32,
15	    pub status: String,
16	    pub message: String,
17	}
18	
19	/// A report from one of the 5 Eyes.
20	#[derive(Debug, Clone)]
21	pub struct EyeReportEvent {
22	    pub eye_name: String,
23	    pub goal_id: Uuid,
24	    pub confidence: f32,
25	    pub content: String,
26	}
27	
28	/// Fan-out bus for goal state updates.
29	pub struct GoalEventBus {
30	    tx: broadcast::Sender<GoalUpdate>,
31	}
32	
33	impl GoalEventBus {
34	    #[must_use] 
35	    pub fn new(capacity: usize) -> Self {
36	        let (tx, _) = broadcast::channel(capacity);
37	        Self { tx }
38	    }
39	
40	    /// Subscribe to goal updates. Returns a receiver that sees all
41	    /// future publishes.
42	    #[must_use] 
43	    pub fn subscribe(&self) -> broadcast::Receiver<GoalUpdate> {
44	        self.tx.subscribe()
45	    }
46	
47	    /// Publish an update to all subscribers.
48	    pub fn publish(&self, update: GoalUpdate) {
49	        let _ = self.tx.send(update);
50	    }
51	}
52	
53	/// Fan-out bus for eye reports.
54	pub struct EyeReportBus {
55	    tx: broadcast::Sender<EyeReportEvent>,
56	}
57	
58	impl EyeReportBus {
59	    #[must_use] 
60	    pub fn new(capacity: usize) -> Self {
61	        let (tx, _) = broadcast::channel(capacity);
62	        Self { tx }
63	    }
64	
65	    #[must_use] 
66	    pub fn subscribe(&self) -> broadcast::Receiver<EyeReportEvent> {
67	        self.tx.subscribe()
68	    }
69	
70	    pub fn publish(&self, event: EyeReportEvent) {
71	        let _ = self.tx.send(event);
72	    }
73	}
74	
75	/// Combined event bus for the daemon.
76	pub struct EventBus {
77	    pub goals: GoalEventBus,
78	    pub eye_reports: EyeReportBus,
79	}
80	
81	impl EventBus {
82	    #[must_use] 
83	    pub fn new() -> Self {
